  ('elementary-814ced5a-moex-00630', 'elementary-814ced5a', 'elementary-814ced5a-moex-110-e97233f0', 'sub-elementary-814ced5a-01', NULL, 'single_choice', '關於舒伯特所作的鱒魚五重奏（Trout quintet），下列物件在FRBR第一組實體中，各為何者？①舒伯特', '["EmanuelAx與GuarneriStringQuartet所演奏的鱒魚五重奏", "1997年由Deutsche Grammophon發行的鱒魚五重奏錄音光碟", "", "作品（work）、"]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:54+00:00", "source_pdf_sha1": "01909ec3ebcd", "answer_pdf_sha1": "877fe314e062", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00631', 'elementary-814ced5a', 'elementary-814ced5a-moex-110-e97233f0', 'sub-elementary-814ced5a-01', NULL, 'single_choice', '語意網（SemanticWeb），是希望全球資訊網的巨量網頁賦予機器可以存取的詮釋資料（metadata），再 藉由標準、標記語言，以及軟體程式，讓機器可以理解（understand）網頁內容以及網頁間錯綜複雜的關 係。此概念由TimBernersLee在何時提出？', '["1988年", "1998年", "2008年", "2018年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:54+00:00", "source_pdf_sha1": "01909ec3ebcd", "answer_pdf_sha1": "877fe314e062", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00632', 'elementary-814ced5a', 'elementary-814ced5a-moex-110-e97233f0', 'sub-elementary-814ced5a-01', NULL, 'single_choice', '簡單知識組織系統（SKOS）的目標是在知識組織系統設計與應用中，建立包括圖書資訊學在內的不同社 群團體之間的橋樑。對於SKOS的敘述，下列何者錯誤？', '["將概念（concept）與標籤（label）整合為一，不予區分處理", "以主題概念為中心，定義了主題詞表結構中最基本的語意屬性", "使用RDF展現與分享控制詞彙", "概念用URI識別符來辨識"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:54+00:00", "source_pdf_sha1": "01909ec3ebcd", "answer_pdf_sha1": "877fe314e062", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00633', 'elementary-814ced5a', 'elementary-814ced5a-moex-110-e97233f0', 'sub-elementary-814ced5a-01', NULL, 'single_choice', '資源描述框架（Resource Description Framework, RDF）是構成鏈結資料最核心的內涵之一，其運算式的 基本結構是運用三元組（triples）的集合，其中不包含下列何項來敘述資源？', '["主體（subject）", "客體（object）", "補語（complement）", "謂詞（predicate）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:54+00:00", "source_pdf_sha1": "01909ec3ebcd", "answer_pdf_sha1": "877fe314e062", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00634', 'elementary-814ced5a', 'elementary-814ced5a-moex-110-e97233f0', 'sub-elementary-814ced5a-01', NULL, 'single_choice', '圖書館參考模式（LibraryReferenceModel,LRM）共定義五種使用者任務（usertask），其中一項使用者 任務名稱並未出現在 FRBR 的四種使用者任務項目中，而是來自主題權威資料功能需求（Functional RequirementsforSubjectAuthorityData,FRSAD），是下列何項使用者任務名稱？', '["尋找（find）", "探索（explore）", "選擇（select）", "識別（identify）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:54+00:00", "source_pdf_sha1": "01909ec3ebcd", "answer_pdf_sha1": "877fe314e062", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00635', 'elementary-814ced5a', 'elementary-814ced5a-moex-110-e97233f0', 'sub-elementary-814ced5a-01', NULL, 'single_choice', '有關ProgramforCooperativeCataloging的敘述，下列何者錯誤？', '["國際合作編目計畫", "美國國會圖書館主導", "包含書目資料的權威控制處理", "圖書館要先自行培訓好編目館員才能加入"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:54+00:00", "source_pdf_sha1": "01909ec3ebcd", "answer_pdf_sha1": "877fe314e062", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00636', 'elementary-814ced5a', 'elementary-814ced5a-moex-110-b3f42868', 'sub-elementary-814ced5a-02', NULL, 'single_choice', '我國憲法第23條規定：「以上各條列舉之自由權利，除為防止妨害他人自由、避免緊急危難、維持社會', '["比例原則", "法律保留原則", "誠實信用原則", "信賴保護原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:54+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00637', 'elementary-814ced5a', 'elementary-814ced5a-moex-110-b3f42868', 'sub-elementary-814ced5a-02', NULL, 'single_choice', '1989 年國小老師李幸長發起「無殼蝸牛運動」，夜宿臺北市忠孝東路，抗議政府漠視人民的居住權益。 後來，無住屋運動轉型為「崔媽媽基金會」，透過協助弱勢族群解決租屋問題，落實「居者適其屋」的 理念。關於「無殼蝸牛運動」發展到「崔媽媽基金會」之成立，下列敘述何者正確？', '["由非營利組織轉型為營利組織", "原強調利他主義後轉為主張利己導向", "原以公益為使命後轉為重視成本效益", "從倡議的社會運動轉為成立服務性的社團"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:54+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL)
